  <script id="ov-final-script">
    document.addEventListener('DOMContentLoaded', function () {
      var openBtn = document.getElementById('openInterviewModal');
      var closeBtn = document.getElementById('closeInterviewModal');
      var modal = document.getElementById('interviewModal');
      if (openBtn && modal) openBtn.addEventListener('click', function () {
        modal.style.display = 'flex';
      });
      if (closeBtn && modal) {
        closeBtn.addEventListener('click', function () {
          modal.style.display = 'none';
        });
        modal.addEventListener('click', function (e) {
          if (e.target === modal) {
            modal.style.display = 'none';
          }
        });
      }
    });
  </script>
