  <style id="section-grid-bg-fix">
    /* Global Section Grid Background */
    .section,
    .site-section,
    .future-section,
    .landing-section,
    .future-home-hero {
      position: relative !important;
      overflow: hidden;
    }

    .section::before,
    .site-section::before,
    .future-section::before,
    .landing-section::before,
    .future-home-hero::before {
      content: '';
      position: absolute;
      inset: 0;
      pointer-events: none;
      z-index: 1;
      /* Above background color */
      background-image:
        linear-gradient(rgba(0, 0, 0, 0.03) 1px, transparent 1px),
        linear-gradient(90deg, rgba(0, 0, 0, 0.03) 1px, transparent 1px);
      background-size: 60px 60px;
    }

    /* Inverse (Dark) Sections Grid */
    .section.is-inverse::before,
    .is-inverse::before {
      background-image:
        linear-gradient(rgba(255, 255, 255, 0.07) 1px, transparent 1px),
        linear-gradient(90deg, rgba(255, 255, 255, 0.07) 1px, transparent 1px);
    }

    /* Radial Glow Accents (Premium Look) for first section */
    .section:first-of-type::after {
      content: '';
      position: absolute;
      inset: 0;
      pointer-events: none;
      z-index: 1;
      background:
        radial-gradient(circle at 10% 0%, rgba(255, 155, 61, 0.12) 0%, transparent 35%),
        radial-gradient(circle at 100% 15%, rgba(59, 130, 246, 0.08) 0%, transparent 30%);
    }

    /* Keep content safely above the grid and glow */
    .section>.container,
    .section>div,
    .section>header,
    .section>.w-container,
    .future-section>div,
    .future-section>header,
    .site-section>div,
    .landing-section>div,
    .future-home-hero>.container-wrap,
    #founder-block>*,
    #cases-redesign-6>*,
    #faq-section>* {
      position: relative;
      z-index: 2;
    }

    #founder-block,
    #cases-redesign-6,
    #faq-section {
      position: relative !important;
      overflow: hidden;
    }

    #founder-block::before,
    #cases-redesign-6::before,
    #faq-section::before {
      content: '';
      position: absolute;
      inset: 0;
      pointer-events: none;
      z-index: 1;
      background-image:
        linear-gradient(rgba(0, 0, 0, 0.03) 1px, transparent 1px),
        linear-gradient(90deg, rgba(0, 0, 0, 0.03) 1px, transparent 1px);
      background-size: 60px 60px;
    }
  </style>


