  <style id="scroll-animations">
    .anim-bounce {
      opacity: 0;
      transform: scale(0.7) translateY(80px);
      transition: opacity 0.6s ease, transform 0.9s cubic-bezier(0.34, 1.56, 0.64, 1);
      will-change: transform, opacity;
    }

    .anim-bounce.is-visible {
      opacity: 1;
      transform: scale(1) translateY(0);
    }

    .stagger-1 {
      transition-delay: 0.1s;
    }

    .stagger-2 {
      transition-delay: 0.2s;
    }

    .stagger-3 {
      transition-delay: 0.3s;
    }

    .stagger-4 {
      transition-delay: 0.4s;
    }

    .stagger-5 {
      transition-delay: 0.5s;
    }

    .stagger-6 {
      transition-delay: 0.6s;
    }

    /* Glow Pulse — pain section */
    .glow-left {
      opacity: 0;
      filter: blur(8px);
      transform: translateY(30px);
      transition: all .9s cubic-bezier(.22, 1, .36, 1);
    }

    .glow-left.is-visible {
      opacity: 1;
      filter: blur(0);
      transform: translateY(0);
    }

    .glow-item {
      opacity: 0;
      transform: translateY(30px) scale(0.96);
      transition: all .6s cubic-bezier(.22, 1, .36, 1);
    }

    .glow-item.is-visible {
      opacity: 1;
      transform: translateY(0) scale(1);
    }

    .glow-item.is-visible .pain-acc-num {
      animation: glow-pulse 1.2s ease forwards;
    }

    @keyframes glow-pulse {
      0% {
        text-shadow: 0 0 0 rgba(249, 115, 22, 0);
        transform: scale(1);
      }

      50% {
        text-shadow: 0 0 20px rgba(249, 115, 22, .6);
        transform: scale(1.15);
      }

      100% {
        text-shadow: 0 0 6px rgba(249, 115, 22, .2);
        transform: scale(1);
      }
    }

    #pain-section .pain-acc-num {
      display: inline-block;
    }

    #pain-section .pain-acc-item,
    #pain-section .pain-acc-head {
      overflow: visible !important;
    }

    #pain-section .pain-acc-num {
      position: relative;
      z-index: 1;
    }

    .glow-stagger-1 {
      transition-delay: .08s;
    }

    .glow-stagger-2 {
      transition-delay: .18s;
    }

    .glow-stagger-3 {
      transition-delay: .28s;
    }

    .glow-stagger-4 {
      transition-delay: .38s;
    }

    .glow-stagger-5 {
      transition-delay: .48s;
    }

    .glow-stagger-6 {
      transition-delay: .58s;
    }

    /* Zigzag — why-us section */
    .zig-head {
      opacity: 0;
      transform: translateY(30px);
      transition: all .7s cubic-bezier(.22, 1, .36, 1);
    }

    .zig-head.is-visible {
      opacity: 1;
      transform: translateY(0);
    }

    .zig-row .why-row-text {
      opacity: 0;
      transform: translateX(-60px);
      transition: all .8s cubic-bezier(.22, 1, .36, 1);
    }

    .zig-row .why-row-img {
      opacity: 0;
      transform: translateX(60px);
      transition: all .8s cubic-bezier(.22, 1, .36, 1) .15s;
    }

    .zig-row:nth-child(even) .why-row-text {
      transform: translateX(60px);
    }

    .zig-row:nth-child(even) .why-row-img {
      transform: translateX(-60px);
    }

    .zig-row.is-visible .why-row-text,
    .zig-row.is-visible .why-row-img {
      opacity: 1;
      transform: translateX(0);
    }

    /* Cinematic Split — founder section */
    .cine-photo {
      opacity: 0;
      transform: translateX(-80px) scale(0.95);
      transition: all 1s cubic-bezier(.22, 1, .36, 1);
    }

    .cine-photo.is-visible {
      opacity: 1;
      transform: translateX(0) scale(1);
    }

    .cine-ey {
      opacity: 0;
      transform: translateY(20px);
      transition: all .6s ease .3s;
    }

    .cine-head {
      opacity: 0;
      transform: translateY(30px);
      transition: all .7s ease .4s;
    }

    .cine-quote {
      opacity: 0;
      transform: translateX(40px);
      transition: all .7s ease .55s;
    }

    .cine-name {
      opacity: 0;
      transition: opacity .5s ease .7s;
    }

    .cine-role {
      opacity: 0;
      transition: opacity .5s ease .75s;
    }

    .cine-facts {
      opacity: 0;
      transform: translateY(20px);
      transition: all .6s ease .85s;
    }

    .cine-photo.is-visible~.founder-split-text .cine-ey,
    .cine-photo.is-visible~.founder-split-text .cine-head,
    .cine-photo.is-visible~.founder-split-text .cine-quote,
    .cine-photo.is-visible~.founder-split-text .cine-name,
    .cine-photo.is-visible~.founder-split-text .cine-role,
    .cine-photo.is-visible~.founder-split-text .cine-facts {
      opacity: 1;
      transform: translateX(0) translateY(0);
    }

    /* Typewriter + Clip — interview section */
    .tw-ey {
      opacity: 0;
      clip-path: inset(0 100% 0 0);
      transition: all .5s ease .1s;
    }

    .tw-title {
      opacity: 0;
      clip-path: inset(0 100% 0 0);
      transition: all .7s ease .25s;
    }

    .tw-sub {
      opacity: 0;
      transition: opacity .5s ease .5s;
    }

    .tw-head.is-visible .tw-ey {
      opacity: 1;
      clip-path: inset(0 0% 0 0);
    }

    .tw-head.is-visible .tw-title {
      opacity: 1;
      clip-path: inset(0 0% 0 0);
    }

    .tw-head.is-visible .tw-sub {
      opacity: 1;
    }

    .tw-card {
      opacity: 0;
      clip-path: inset(8% 8% 8% 8% round 20px);
      transition: all 1s cubic-bezier(.22, 1, .36, 1) .4s;
    }

    .tw-card.is-visible {
      opacity: 1;
      clip-path: inset(0% 0% 0% 0% round 20px);
    }

    /* Cascade Rise — cases section */
    .cr-head {
      opacity: 0;
      transform: translateY(25px);
      transition: all .7s cubic-bezier(.22, 1, .36, 1);
    }

    .cr-head.is-visible {
      opacity: 1;
      transform: translateY(0);
    }

    .cr-featured {
      opacity: 0;
      transform: translateY(40px);
      transition: all .8s cubic-bezier(.22, 1, .36, 1) .2s;
    }

    .cr-featured.is-visible {
      opacity: 1;
      transform: translateY(0);
    }

    .cr-featured .cs-feat-box {
      opacity: 0;
      transform: translateY(15px);
    }

    .cr-featured.is-visible .cs-feat-box {
      animation: cr-boxPop .5s cubic-bezier(.22, 1, .36, 1) both;
    }

    .cr-featured.is-visible .cs-feat-box:nth-child(1) {
      animation-delay: .5s;
    }

    .cr-featured.is-visible .cs-feat-box:nth-child(2) {
      animation-delay: .65s;
    }

    .cr-featured.is-visible .cs-feat-box:nth-child(3) {
      animation-delay: .8s;
    }

    @keyframes cr-boxPop {
      0% {
        opacity: 0;
        transform: translateY(15px);
      }

      100% {
        opacity: 1;
        transform: translateY(0);
      }
    }

    .cr-mini {
      opacity: 0;
      transform: translateY(30px);
      transition: all .6s cubic-bezier(.22, 1, .36, 1);
    }

    .cr-mini.is-visible {
      opacity: 1;
      transform: translateY(0);
    }

    .cr-mini:nth-child(1) {
      transition-delay: .1s;
    }

    .cr-mini:nth-child(2) {
      transition-delay: .25s;
    }

    .cr-mini:nth-child(3) {
      transition-delay: .4s;
    }

    /* 3D Tilt — useful section */
    .v4-top {
      opacity: 0;
      transform: translateY(20px);
      transition: all .6s cubic-bezier(.22, 1, .36, 1);
    }

    .v4-top.is-visible {
      opacity: 1;
      transform: translateY(0);
    }

    #useful-business-block .uf-grid {
      perspective: 1000px;
    }

    .v4-card {
      opacity: 0;
      transform: perspective(1000px) rotateY(-12deg) translateZ(-40px);
      transition: all .8s cubic-bezier(.22, 1, .36, 1);
    }

    .v4-card.is-visible {
      opacity: 1;
      transform: perspective(1000px) rotateY(0) translateZ(0);
    }

    .v4-card:nth-child(1) {
      transition-delay: .1s;
    }

    .v4-card:nth-child(2) {
      transition-delay: .25s;
    }

    .v4-card:nth-child(3) {
      transition-delay: .4s;
    }

    .v4-card.is-visible .uf-card-bg {
      animation: v4-bgShimmer 3s ease-in-out .8s infinite;
    }

    @keyframes v4-bgShimmer {

      0%,
      100% {
        filter: brightness(1);
      }

      50% {
        filter: brightness(1.15);
      }
    }

    /* Slide Split — FAQ section */
    .faq-l-anim {
      opacity: 0;
      transform: translateX(-40px);
      transition: all .8s cubic-bezier(.22, 1, .36, 1);
    }

    .faq-l-anim.is-visible {
      opacity: 1;
      transform: translateX(0);
    }

    .faq-i-anim {
      opacity: 0;
      transform: translateX(40px);
      transition: all .8s cubic-bezier(.22, 1, .36, 1);
    }

    .faq-i-anim.is-visible {
      opacity: 1;
      transform: translateX(0);
    }

    .faq-i-anim:nth-child(1) {
      transition-delay: .1s;
    }

    .faq-i-anim:nth-child(2) {
      transition-delay: .2s;
    }

    .faq-i-anim:nth-child(3) {
      transition-delay: .3s;
    }

    .faq-i-anim:nth-child(4) {
      transition-delay: .4s;
    }

    .faq-i-anim:nth-child(5) {
      transition-delay: .5s;
    }

    .faq-i-anim:nth-child(6) {
      transition-delay: .6s;
    }

    .faq-i-anim:nth-child(7) {
      transition-delay: .7s;
    }

    .faq-i-anim:nth-child(8) {
      transition-delay: .8s;
    }

    /* Zoom In Focus — CTA section */
    .v1-card-cta {
      opacity: 0;
      scale: .94;
      transition: all .8s cubic-bezier(.22, 1, .36, 1);
    }

    .v1-card-cta.is-visible {
      opacity: 1;
      scale: 1;
    }

    .v1-content-cta {
      opacity: 0;
      transform: translateY(20px);
      transition: all .6s ease .3s;
    }

    .v1-card-cta.is-visible .v1-content-cta {
      opacity: 1;
      transform: translateY(0);
    }

    .v1-right-cta {
      opacity: 0;
      transform: translateY(20px);
      transition: all .6s ease .45s;
    }

    .v1-card-cta.is-visible .v1-right-cta {
      opacity: 1;
      transform: translateY(0);
    }

    :root {
      --site-bg: #f4f7fb;
      --site-bg-soft: #f8fafc;
      --site-surface: rgba(255, 255, 255, 0.94);
      --site-surface-strong: #ffffff;
      --site-border: #dbe4f0;
      --site-border-strong: #cdd8e6;
      --site-text: #0f172a;
      --site-text-soft: #475569;
      --site-text-muted: #64748b;
      --site-brand: #ff9b3d;
      --site-brand-soft: #fff4e8;
      --site-dark: #0f172a;
      --site-dark-2: #111827;
      --site-radius-xl: 24px;
      --site-radius-2xl: 32px;
      --site-shadow: 0 18px 45px rgba(15, 23, 42, 0.08);
      --site-shadow-soft: 0 10px 24px rgba(15, 23, 42, 0.06);
      --site-container: 1180px;
      --font-sans: 'Manrope', 'Segoe UI', ui-sans-serif, system-ui, sans-serif;
    }

    .container-wrap {
      width: 100%;
      max-width: var(--site-container);
      margin-inline: auto;
      padding-inline: 20px;
    }

    /* Future Home Hero Styles */
    .future-home-hero {
      min-height: calc(100vh - 84px);
      display: flex;
      align-items: center;
      position: relative;
      overflow: clip;
      background: #ffffff !important;
    }

    .future-mesh-1 {
      position: absolute;
      top: -100px;
      right: -100px;
      width: 500px;
      height: 500px;
      background: radial-gradient(circle, rgba(255, 138, 42, 0.12) 0%, transparent 70%);
      filter: blur(80px);
      pointer-events: none;
      z-index: 1;
    }

    .future-mesh-2 {
      position: absolute;
      top: 0;
      bottom: 0;
      left: 0;
      width: 45%;
      background: linear-gradient(to right, rgba(255, 138, 42, 0.25), transparent);
      filter: blur(20px);
      pointer-events: none;
      z-index: 1;
    }

    .future-home-hero-grid {
      position: relative;
      z-index: 10;
      display: grid;
      grid-template-columns: minmax(0, 1.15fr) minmax(340px, 0.85fr);
      gap: 48px;
      align-items: center;
    }

    .future-home-copy {
      max-width: 820px;
    }

    .future-home-eyebrow {
      display: inline-flex;
      align-items: center;
      gap: 10px;
      padding: 10px 16px;
      border: 1px solid rgba(15, 15, 15, 0.08);
      border-radius: 999px;
      background: rgba(255, 255, 255, 0.86);
      color: #6f6f6f;
      font-size: 11px;
      font-weight: 600;
      letter-spacing: 0.16em;
      text-transform: uppercase;

      /* Animation Base */
      opacity: 0;
      transform: translateY(20px);
      transition: opacity 1s ease 0.4s, transform 1s cubic-bezier(0.19, 1, 0.22, 1) 0.4s;
    }

    .is-glass-loaded .future-home-eyebrow {
      opacity: 1;
      transform: translateY(0);
    }

    .future-home-eyebrow::before {
      content: '';
      width: 6px;
      height: 6px;
      border-radius: 999px;
      background: #ff6a00;
      box-shadow: 0 0 10px #ff6a00;
    }

    html body section.future-home-hero h1.future-home-title {
      margin-top: 18px;
      font-family: var(--font-sans) !important;
      font-size: 90px !important;
      font-weight: 900 !important;
      line-height: 0.96 !important;
      letter-spacing: -0.045em !important;
      color: #0f0f0f !important;
      max-width: none;
      text-wrap: balance;

      /* Glass Reveal Initial State */
      opacity: 0;
      filter: blur(40px);
      transform: scale(1.1) translateZ(40px);
      transition: opacity 1.5s cubic-bezier(0.19, 1, 0.22, 1),
        filter 1.8s cubic-bezier(0.19, 1, 0.22, 1),
        transform 1.6s cubic-bezier(0.19, 1, 0.22, 1);
      will-change: filter, transform, opacity;
    }

    /* Entrance Animation */
    .future-home-hero.is-glass-loaded .future-home-title {
      opacity: 1;
      filter: blur(0);
      transform: scale(1) translateZ(0);
    }

    .future-home-title span {
      display: block;
      color: #ff6a00 !important;
      text-shadow: 0 0 10px rgba(255, 106, 0, 0.16), 0 0 24px rgba(255, 106, 0, 0.14);
    }

    .future-home-subtitle {
      margin-top: 28px;
      max-width: 640px;
      color: #555 !important;
      font-size: 20px;
      line-height: 1.72;
      font-weight: 450;

      /* Animation Base */
      opacity: 0;
      transform: translateY(20px);
      transition: opacity 1s ease 0.6s, transform 1s cubic-bezier(0.19, 1, 0.22, 1) 0.6s;
    }

    .is-glass-loaded .future-home-subtitle {
      opacity: 1;
      transform: translateY(0);
    }

    .future-home-actions {
      display: flex;
      flex-wrap: wrap;
      gap: 14px;
      margin-top: 42px;

      /* Animation Base */
      opacity: 0;
      transform: translateY(20px);
      transition: opacity 1s ease 0.8s, transform 1s cubic-bezier(0.19, 1, 0.22, 1) 0.8s;
    }

    .is-glass-loaded .future-home-actions {
      opacity: 1;
      transform: translateY(0);
    }

    .future-btn {
