    .future-home-visual {
      position: relative;
      min-height: 620px;
      display: flex;
      align-items: center;
      justify-content: center;
      filter: drop-shadow(0 24px 64px rgba(0, 0, 0, 0.18)) drop-shadow(0 8px 24px rgba(0, 0, 0, 0.12));
    }

    .future-home-orb {
      position: absolute;
      width: min(100%, 560px);
      aspect-ratio: 1;
      border-radius: 999px;
      background: radial-gradient(circle at 42% 38%, rgba(255, 106, 0, 0.42), rgba(255, 106, 0, 0.08) 28%, rgba(255, 255, 255, 0.08) 44%, transparent 72%), radial-gradient(circle at 50% 50%, rgba(255, 255, 255, 0.7), rgba(255, 255, 255, 0) 62%);
      opacity: 1;
    }

    .future-home-orb::before,
    .future-home-orb::after {
      content: '';
      position: absolute;
      inset: 36px;
      border-radius: inherit;
      border: 1px solid rgba(15, 15, 15, 0.08);
    }

    .future-home-orb::after {
      inset: 86px;
      border-color: rgba(255, 106, 0, 0.25);
      box-shadow: 0 0 28px rgba(255, 106, 0, 0.15);
    }

    .future-home-orb-lines {
      position: absolute;
      inset: 0;
      pointer-events: none;
