        display: flex;
        align-items: center;
        justify-content: space-between;
        padding: 12px 20px;
        border-top: 1px solid rgba(255,255,255,.06);
        margin-top: 4px;
      }
      .cmd-mob-bottom .cmd-nav-socials {
        display: flex !important;
        flex-basis: auto;
        padding: 0;
      }
      .cmd-mob-cta {
        padding: 10px 20px;
        background: #f97316;
        color: #fff !important;
        border-radius: 10px;
        font-size: 13px;
        font-weight: 600;
        text-decoration: none;
        transition: background .2s;
      }
      .cmd-mob-cta:hover { background: #ea6c0e; }

      /* --- Hero --- */
      .future-home-hero {
        padding: 32px 0 56px !important;
      }
      .future-home-hero-grid {
        grid-template-columns: 1fr !important;
        gap: 24px !important;
      }
      html body section.future-home-hero h1.future-home-title,
      .future-home-title {
        font-size: 68px !important;
        line-height: 1.05 !important;
      }
      .future-home-subtitle {
        font-size: 15px !important;
      }
      .future-home-visual {
        min-height: 280px !important;
      }
      .future-home-actions {
        display: flex;
        flex-direction: column;
      }
      .future-home-actions .future-btn {
        width: 100%;
        text-align: center;
        padding: 16px 24px;
      }
      .future-home-panel {
        display: none !important;
      }
      .future-home-orb-lines {
        display: none !important;
      }

      /* --- Pain Points --- */
      #pain-section .container {
        padding: 0 16px !important;
      }
      .pain-heading {
        font-size: 26px !important;
      }
      .pain-acc-head h3 {
        font-size: 20px !important;
      }
      .pain-desc {
        font-size: 14px !important;
      }
      .pain-acc-body p {
        font-size: 15px !important;
      }

      /* --- Services --- */
      .future-card-grid {
        grid-template-columns: 1fr !important;
        gap: 12px !important;
      }
      .future-service-card {
        min-height: 180px !important;
        padding: 20px !important;
      }
      .future-service-copy h3 {
        font-size: 18px !important;
      }

      /* --- Trust Marquee --- */
      #trust-compact-block .trust-m-item {
        padding: 0 18px;
        font-size: 13px;
      }

      /* --- Founder --- */
      .founder-split {
        grid-template-columns: 1fr !important;
      }
      .founder-split-photo {
        height: 280px !important;
      }
      .founder-split-text {
        padding: 28px 16px !important;
      }
      .founder-split-heading {
        font-size: 24px !important;
      }
      .founder-split-quote {
        font-size: 15px !important;
      }
      .founder-split-name {
        font-size: 18px !important;
        margin-bottom: 14px !important;
      }
      .founder-split-facts {
        gap: 16px !important;
      }
      .founder-split-val {
        font-size: 24px !important;
      }
      .founder-split-lbl {
        font-size: 12px !important;
      }

      /* --- Interview --- */
      #amocrm-interview-block {
        padding: 64px 0 !important;
      }
      .iv-wrap {
        padding: 0 16px !important;
      }
      .iv-title {
        font-size: 24px !important;
      }
      .iv-card {
        flex-direction: column !important;
        padding: 20px !important;
        gap: 16px !important;
      }
      .iv-card-title {
        font-size: 20px !important;
      }
      .iv-preview,
      .iv-preview-wrap {
        width: 100% !important;
        height: 200px !important;
        min-height: auto !important;
      }

      /* --- Cases --- */
      #cases-redesign-6 {
        padding: 64px 0 !important;
      }
      .cs-wrap {
        padding: 0 16px !important;
      }
      .cs-title {
        font-size: 26px !important;
      }
      .cs-featured {
        padding: 20px !important;
        border-radius: 20px !important;
      }
      .cs-featured-title {
        font-size: 20px !important;
      }
      .cs-featured-grid {
        grid-template-columns: 1fr !important;
        gap: 12px !important;
      }
      .cs-mini-grid {
        grid-template-columns: 1fr !important;
        gap: 12px !important;
      }
      .cs-mini {
        padding: 18px !important;
      }

      /* --- Testimonials --- */
      .future-review-card {
        padding: 24px !important;
        gap: 16px !important;
      }
      .future-review-text {
        font-size: 15px !important;
      }
      .client-info .avatar {
        width: 50px !important;
        height: 50px !important;
      }
      .client-info .meta h4 {
        font-size: 16px !important;
      }
      .client-info .meta span {
        font-size: 13px !important;
      }

      /* --- Useful / Resources --- */
      #useful-business-block {
        padding: 64px 0 !important;
      }
      .uf-wrap {
        padding: 0 16px !important;
      }
      .uf-title {
        font-size: 26px !important;
      }
      .uf-grid {
        grid-template-columns: 1fr !important;
        gap: 12px !important;
      }
      .uf-card {
        min-height: 280px !important;
      }
      .uf-card h3 {
        font-size: 20px !important;
      }
      .uf-card p {
        font-size: 14px !important;
      }

      /* --- FAQ --- */
      section#faq-section {
        padding: 64px 0 !important;
      }
      .faq-layout-wrap {
        padding: 0 16px !important;
      }
      .faq-left-title {
        font-size: 24px !important;
      }
      .faq-left-desc {
        font-size: 14px !important;
      }
      .faq-acc-q span {
        font-size: 18px !important;
        line-height: 1.22 !important;
      }
      .faq-acc-ans-inner {
        font-size: 14px !important;
      }

      /* --- Contact Form --- */
      .future-contact-panel {
        padding: 24px 16px !important;
        border-radius: 24px !important;
        grid-template-columns: 1fr !important;
      }
      .future-contact-title {
        font-size: 28px !important;
      }
      .future-form-card {
        padding: 20px !important;
        border-radius: 20px !important;
      }
      .future-form-grid {
        grid-template-columns: 1fr !important;
      }
      .future-form-field input,
      .future-form-field textarea {
        font-size: 16px !important; /* prevents iOS zoom */
      }
      .future-form-submit {
        width: 100%;
        min-height: 48px;
      }

      /* --- Footer --- */
      footer#new-footer {
        padding: 48px 0 24px !important;
      }
      .nf-wrap {
        padding: 0 16px !important;
      }
      .nf-grid {
        grid-template-columns: 1fr !important;
        gap: 24px !important;
      }
      .nf-social {
        width: 36px !important;
        height: 36px !important;
      }
      .nf-social svg {
        width: 16px !important;
        height: 16px !important;
      }

      /* --- Global section spacing --- */
      .future-section {
        padding: 64px 0 !important;
      }
      .future-section-head {
        margin-bottom: 32px !important;
      }
      .future-section-title {
        font-size: 26px !important;
      }
      .container-wrap {
        padding-left: 16px !important;
        padding-right: 16px !important;
      }

      /* --- Touch targets --- */
      .pain-cta, .faq-left-btn, .cs-featured-btn,
      .future-btn, .future-form-submit,
      .nf-list a, .faq-acc-q {
        min-height: 44px;
        display: inline-flex;
        align-items: center;
      }
    }

    /* ===== SMALL MOBILE — max-width: 480px ===== */
    @media (max-width: 480px) {
      /* Hero */
      html body section.future-home-hero h1.future-home-title,
      .future-home-title {
        font-size: 54px !important;
      }
      .future-home-visual {
        min-height: 220px !important;
      }

      /* Pain Points */
      .pain-heading {
        font-size: 22px !important;
      }
      #pain-section .container {
        padding: 0 12px !important;
      }

      /* Founder */
      .founder-split-photo {
        height: 220px !important;
      }
      .founder-split-heading {
        font-size: 22px !important;
      }

      /* Interview */
      .iv-title {
        font-size: 22px !important;
      }
      .iv-card {
        padding: 16px !important;
      }

      /* Cases */
      .cs-title {
        font-size: 22px !important;
      }
      .cs-featured-title {
        font-size: 18px !important;
      }

      /* FAQ */
      .faq-left-title {
        font-size: 22px !important;
      }

      /* Contact Form */
      .future-contact-title {
        font-size: 24px !important;
      }
      .future-contact-panel {
        padding: 20px 12px !important;
        border-radius: 20px !important;
      }

      /* Useful */
      .uf-title {
        font-size: 22px !important;
      }
      .uf-card {
        min-height: 240px !important;
      }

      /* Section titles */
      .future-section-title {
        font-size: 22px !important;
      }

      /* Global spacing */
      .container-wrap {
        padding-left: 12px !important;
        padding-right: 12px !important;
      }
      .iv-wrap, .cs-wrap, .uf-wrap, .faq-layout-wrap, .nf-wrap {
        padding: 0 12px !important;
      }
    }
  </style>

  {!! $headPlugins ?? '' !!}
</head>

