  <style id="future-services-style">
    .future-section {
      padding: 80px 0 100px;
      background: #f8fafc !important;
      background-image: none !important;
    }

    .future-section-head {
      margin-bottom: 48px;
    }

    .future-section-title {
      font-family: 'Inter', 'Albert Sans', sans-serif !important;
      font-size: 36px !important;
      font-weight: 700 !important;
      line-height: 1.15 !important;
      letter-spacing: -0.025em !important;
      color: #111 !important;
    }

    .cs-ey {
      font-size: 12px !important;
      font-weight: 600 !important;
      color: #f97316 !important;
      text-transform: uppercase;
      letter-spacing: .1em;
      margin-bottom: 12px;
    }

    .future-card-grid {
      display: grid;
      grid-template-columns: repeat(2, minmax(0, 1fr));
      gap: 20px;
    }

    /* Layer 1: Dedicated Reveal Container (Handles Scroll Animation) */
    .future-service-reveal {
      opacity: 0;
      transform: translateY(40px);
      height: 100%;
      display: flex;
      transition: opacity 1.2s cubic-bezier(0.23, 1, 0.32, 1),
        transform 1.2s cubic-bezier(0.23, 1, 0.32, 1);
      will-change: transform, opacity;
    }

    .is-directions-loaded .future-service-reveal {
      opacity: 1;
      transform: translateY(0);
    }

    /* Staggered entry for the REVEAL layer */
    .is-directions-loaded .future-service-reveal:nth-child(1) {
      transition-delay: 0.1s;
    }

    .is-directions-loaded .future-service-reveal:nth-child(2) {
      transition-delay: 0.25s;
    }

    .is-directions-loaded .future-service-reveal:nth-child(3) {
      transition-delay: 0.4s;
    }

    .is-directions-loaded .future-service-reveal:nth-child(4) {
      transition-delay: 0.55s;
    }

    /* Layer 2: The Original Service Card (Handles Hover ONLY) */
    .future-service-card {
      min-height: 260px;
      height: 100%;
      width: 100%;
      padding: 30px;
      border-radius: 30px;
      background: #ffffff;
      border: 1px solid rgba(15, 15, 15, 0.05);
      box-shadow: 0 8px 32px rgba(0, 0, 0, 0.08), 0 2px 8px rgba(0, 0, 0, 0.04);
      display: flex;
      flex-direction: column;
      justify-content: flex-start;
      gap: 18px;
      text-decoration: none;
      position: relative;

      /* Pure Hover Transition - Fast and Smooth as originally */
      transition: transform 0.4s ease, box-shadow 0.4s ease, border-color 0.4s ease;
    }

    .future-service-card:hover {
      transform: translateY(-8px);
      border-color: rgba(255, 138, 42, 0.2);
      box-shadow: 0 25px 60px rgba(0, 0, 0, 0.07);
    }

    .future-service-kicker {
      color: #ff8a2a;
      font-size: 12px;
      font-weight: 700;
      letter-spacing: 0.12em;
      text-transform: uppercase;
      margin-bottom: 10px;
    }

    .future-service-copy h3 {
      font-family: var(--font-sans) !important;
      font-size: clamp(22px, 1.9vw, 28px) !important;
      font-weight: 700 !important;
      line-height: 1.12 !important;
      letter-spacing: -0.03em !important;
      color: #0f172a !important;
      margin-top: 0;
      max-width: 48ch;
    }

    .future-service-desc {
      display: none;
    }

    .future-service-actions {
      margin-top: auto;
      display: flex;
      flex-direction: column;
      align-items: flex-start;
      gap: 10px;
      padding-top: 8px;
    }

    .future-service-link {
      font-size: 12px;
      font-weight: 700;
      letter-spacing: 0.08em;
      text-transform: uppercase;
      color: #0f172a;
      opacity: 0.4;
      transition: all 0.2s;
      text-decoration: none;
    }

    .future-service-card:hover .future-service-link {
      color: #ff8a2a;
      opacity: 1;
      transform: translateX(4px);
    }

    .future-service-case-link {
      font-size: 12px;
      font-weight: 700;
      letter-spacing: 0.08em;
      text-transform: uppercase;
      color: #64748b;
      text-decoration: none;
      transition: color 0.2s ease, transform 0.2s ease;
    }

    .future-service-card:hover .future-service-case-link {
      color: #0f172a;
      transform: translateX(4px);
    }

    @media (max-width: 768px) {
      .future-card-grid {
        grid-template-columns: 1fr;
      }

      .future-service-card {
        padding: 24px;
        min-height: 200px;
      }
    }

    .future-section {
      padding: 44px 0 144px;
    }

    /* Unified Section Spacing (Top Padding) */
    #pain-section,
    #home-directions,
    #market-trust,
    #cases-redesign-6,
    #home-reviews,
    #faq-section {
      padding-top: 144px !important;
    }

    #home-directions {
      padding-bottom: 188px !important;
    }

    /* Unified Typography System (Sections 2-9) */

    /* 1. Eyebrows (Labels) */
    .pain-eyebrow,
    .cs-ey,
    .founder-split-ey,
    .iv-ey,
    .tw-ey,
    .uf-ey,
    .faq-left-ey {
      font-size: 13px !important;
      font-weight: 700 !important;
      letter-spacing: 0.12em !important;
      text-transform: uppercase !important;
      margin-bottom: 12px !important;
      display: block !important;
      font-family: 'Inter', sans-serif !important;
      color: #ff8a2a !important;
      /* Unified accent color */
    }

    /* 2. Section Titles (H2) */
    .pain-heading,
    .future-section-title,
    .founder-split-heading,
    .market-trust-title,
    .iv-title,
    .tw-title,
    .cs-title,
    .uf-title,
    .faq-left-title {
      font-size: clamp(30px, 4vw, 42px) !important;
      font-weight: 700 !important;
      letter-spacing: -0.02em !important;
      line-height: 1.1 !important;
      margin-top: 0 !important;
      margin-bottom: 24px !important;
      font-family: 'Inter', sans-serif !important;
    }

    /* 3. Descriptions (P) */
    .pain-desc,
    .founder-desc,
    .founder-split-role,
    .iv-sub,
    .tw-sub,
    .cs-mini-text,
    .uf-desc,
    .faq-left-desc {
      font-size: 16px !important;
      font-weight: 400 !important;
      line-height: 1.6 !important;
      font-family: 'Inter', sans-serif !important;
      max-width: 600px;
    }

    .iv-sub,
    .tw-sub,
    .founder-desc {
      text-align: center !important;
      margin-left: auto !important;
      margin-right: auto !important;
    }

    /* Color handle for light/dark descriptions */
    #pain-section .pain-desc,
    #amocrm-interview-block .iv-sub,
    #amocrm-interview-block .tw-sub,
    #useful-business-block .uf-desc {
      color: rgba(255, 255, 255, 0.6) !important;
    }

    #cases-redesign-6 .cs-mini-text,
    #faq-section .faq-left-desc {
      color: rgba(15, 15, 15, 0.6) !important;
    }

    #home-directions {
      padding-bottom: 44px !important;
    }



    .future-review-grid {
      display: grid;
      grid-template-columns: repeat(4, minmax(0, 1fr));
      gap: 18px;
      align-items: start;
      margin-top: 32px;
    }

    .future-review-card {
      padding: 18px !important;
      border-radius: 30px !important;
      background: rgba(255, 255, 255, 0.95) !important;
      border: 1px solid rgba(15, 15, 15, 0.06) !important;
      box-shadow: 0 8px 32px rgba(0, 0, 0, 0.08), 0 2px 8px rgba(0, 0, 0, 0.04) !important;
      display: flex !important;
      flex-direction: column !important;
      gap: 16px !important;
      transition: transform 0.6s cubic-bezier(0.4, 0, 0.2, 1), box-shadow 0.6s ease, border-color 0.6s ease, opacity 0.8s ease;
      min-height: 0;
      opacity: 0;
      transform: translateX(-20px);
      position: relative;
      overflow: hidden;
      width: 100%;
      text-align: left;
      appearance: none;
      cursor: pointer;
    }

    .future-review-card.is-visible {
      opacity: 1;
      transform: translateX(0);
    }

    /* Optical Trace Sweep Effect */
    .future-review-card::after {
      content: '';
      position: absolute;
      top: 0;
      left: -150%;
      width: 100%;
      height: 100%;
      background: linear-gradient(90deg, transparent, rgba(255, 138, 42, 0.1), transparent);
      transform: skewX(-20deg);
      pointer-events: none;
    }

    .future-review-card.is-visible::after {
      animation: sweep-effect 1.5s forwards;
      animation-delay: 0.8s;
    }

    @keyframes sweep-effect {
      100% {
        left: 150%;
      }
    }

    .future-review-card:nth-child(2) {
      transition-delay: 0.15s;
    }

    .future-review-card:nth-child(3) {
      transition-delay: 0.3s;
    }

    .future-review-card:hover {
      transform: translateY(-8px) !important;
      box-shadow: 0 30px 60px rgba(0, 0, 0, 0.08);
      border-color: rgba(255, 106, 0, 0.15);
    }

    .future-review-video {
      position: relative;
      aspect-ratio: 9 / 16;
      border-radius: 24px;
      overflow: hidden;
      background:
        radial-gradient(circle at 50% 0%, rgba(255, 138, 42, 0.18), transparent 32%),
        linear-gradient(180deg, #f4f6f8 0%, #e8edf3 100%);
      border: 1px solid rgba(15, 15, 15, 0.05);
    }

    .future-review-video img {
      width: 100%;
      height: 100%;
      object-fit: cover;
      display: block;
    }

