      var track = document.getElementById('useful-track');
      if (!track) return;

      var left = document.querySelector('#useful-business-block .checklists-arrow.left');
      var right = document.querySelector('#useful-business-block .checklists-arrow.right');
      var step = function () {
        return Math.max(track.clientWidth * 0.72, 320);
      };

      if (left) {
        left.addEventListener('click', function () {
          track.scrollBy({ left: -step(), behavior: 'smooth' });
        });
      }

      if (right) {
        right.addEventListener('click', function () {
          track.scrollBy({ left: step(), behavior: 'smooth' });
        });
      }
    })();
  </script>
