  <script>
    // Force footer styles (run after Webflow JS)
    function forceFooterStyles() {
      var f = document.getElementById('new-footer');
      if (!f) return;
      f.querySelectorAll('*').forEach(function (n) {
        if (n.closest('svg') || n.tagName === 'svg' || n.tagName === 'SVG') return;
        n.style.setProperty('visibility', 'visible', 'important');
        n.style.setProperty('opacity', '1', 'important');
      });
      f.querySelectorAll('.nf-brand-name').forEach(function (n) { n.style.setProperty('color', '#fff', 'important'); });
      f.querySelectorAll('.nf-brand-text').forEach(function (n) { n.style.setProperty('color', 'rgba(255,255,255,.4)', 'important'); });
      f.querySelectorAll('.nf-col-title').forEach(function (n) { n.style.setProperty('color', 'rgba(255,255,255,.3)', 'important'); });
      f.querySelectorAll('.nf-list a').forEach(function (n) { n.style.setProperty('color', 'rgba(255,255,255,.5)', 'important'); });
      f.querySelectorAll('.nf-bottom, .nf-bottom span').forEach(function (n) { n.style.setProperty('color', 'rgba(255,255,255,.25)', 'important'); });
    }
    forceFooterStyles();
    setTimeout(forceFooterStyles, 100);
    setTimeout(forceFooterStyles, 500);
    setTimeout(forceFooterStyles, 1500);

    // Social icons hover in footer
    document.querySelectorAll('#new-footer .nf-social').forEach(function(a) {
      a.addEventListener('mouseenter', function() {
        a.style.setProperty('color', '#f97316', 'important');
        a.style.setProperty('background', 'rgba(249,115,22,.12)', 'important');
        a.querySelectorAll('svg, svg *').forEach(function(el) {
          if (el.hasAttribute('fill') && el.getAttribute('fill') !== 'none') el.style.setProperty('fill', '#f97316', 'important');
          if (el.hasAttribute('stroke') && el.getAttribute('stroke') !== 'none') el.style.setProperty('stroke', '#f97316', 'important');
        });
      });
      a.addEventListener('mouseleave', function() {
        a.style.setProperty('color', '#fff', 'important');
        a.style.setProperty('background', 'rgba(255,255,255,.05)', 'important');
        a.querySelectorAll('svg, svg *').forEach(function(el) {
          if (el.hasAttribute('fill') && el.getAttribute('fill') !== 'none') el.style.setProperty('fill', 'currentColor', 'important');
          if (el.hasAttribute('stroke') && el.getAttribute('stroke') !== 'none') el.style.setProperty('stroke', 'currentColor', 'important');
        });
      });
    });

    // Force FAQ styles via JS
    (function () {
      var el = document.getElementById('faq-section');
      if (!el) return;
      el.style.cssText = 'display:block!important;background:#fff!important;padding:144px 0!important;font-family:Inter,sans-serif!important;color:#111!important;';
      el.querySelectorAll('*').forEach(function (n) { n.style.visibility = 'visible'; });
      var wrap = el.querySelector('.faq-layout-wrap');
      if (wrap) wrap.style.cssText = 'max-width:1120px;margin:0 auto;padding:0 32px;';
      var layout = el.querySelector('.faq-layout');
      if (layout) layout.style.cssText = 'display:grid;grid-template-columns:.4fr .6fr;gap:56px;align-items:flex-start;';
      var left = el.querySelector('.faq-left');
      if (left) left.style.cssText = 'position:sticky;top:100px;';
      var ey = el.querySelector('.faq-left-ey');
      if (ey) ey.style.cssText = 'font-size:13px;font-weight:700;color:#ff8a2a;text-transform:uppercase;letter-spacing:.12em;margin-bottom:12px;';
      var title = el.querySelector('.faq-left-title');
      if (title) title.style.cssText = 'font-size:42px;font-weight:800;color:#111;letter-spacing:-0.02em;line-height:1.1;margin:0 0 24px 0;';
      var desc = el.querySelector('.faq-left-desc');
      if (desc) desc.style.cssText = 'font-size:17px;line-height:1.6;color:rgba(15,15,15,0.6);margin:0 0 24px 0;';
      var btn = el.querySelector('.faq-left-btn');
      if (btn) btn.style.cssText = 'display:inline-flex;align-items:center;padding:14px 28px;border-radius:14px;background:#ff8a2a;color:#fff;font-size:15px;font-weight:600;line-height:1;text-decoration:none;';
      el.querySelectorAll('.faq-acc-item').forEach(function (item) {
        item.style.cssText = 'border-bottom:1px solid rgba(0,0,0,.06);overflow:hidden;';
      });
      el.querySelectorAll('.faq-acc-q').forEach(function (q) {
        q.style.cssText = 'display:flex;align-items:center;justify-content:space-between;gap:16px;padding:20px 0;cursor:pointer;width:100%;background:none;border:none;font-family:inherit;text-align:left;';
      });
      el.querySelectorAll('.faq-acc-q span').forEach(function (s) {
        s.style.cssText = 'font-size:16px;font-weight:600;color:#111;';
      });
      el.querySelectorAll('.faq-acc-icon').forEach(function (i) {
        i.style.cssText = 'width:28px;height:28px;border-radius:50%;flex-shrink:0;background:rgba(0,0,0,.04);display:flex;align-items:center;justify-content:center;font-size:16px;font-style:normal;color:rgba(0,0,0,.3);transition:all .3s;';
      });
      el.querySelectorAll('.faq-acc-ans').forEach(function (a) {
        a.style.cssText = 'max-height:0;overflow:hidden;transition:max-height .4s ease;';
      });
      el.querySelectorAll('.faq-acc-ans-inner').forEach(function (a) {
        a.style.cssText = 'padding:0 0 18px;font-size:14px;line-height:1.6;color:rgba(0,0,0,.45);';
      });
      // First open
      var firstOpen = el.querySelector('.faq-acc-open');
      if (firstOpen) {
        var ans = firstOpen.querySelector('.faq-acc-ans');
        if (ans) ans.style.maxHeight = '150px';
        var icon = firstOpen.querySelector('.faq-acc-icon');
        if (icon) { icon.style.background = '#f97316'; icon.style.color = '#fff'; icon.style.transform = 'rotate(45deg)'; }
      }
      // First item border-top
      var firstItem = el.querySelector('.faq-acc-item');
      if (firstItem) firstItem.style.borderTop = 'none';
    })();

    document.querySelectorAll('.faq-acc-q').forEach(q => {
      q.addEventListener('click', () => {
        const item = q.parentElement;
        const wasOpen = item.classList.contains('faq-acc-open');
        item.closest('.faq-acc').querySelectorAll('.faq-acc-item').forEach(i => i.classList.remove('faq-acc-open'));
        if (!wasOpen) item.classList.add('faq-acc-open');
      });
    });

