    /* ═══ HERO ANIMATION ═══ */
    /* Hero animations — handled by GSAP in script below */
    header.hero-compact .heading_hero {
      perspective: 600px !important;
    }

    .heading_hero .hero-word {
      display: inline-block !important;
    }
  </style>

  <script id="glass-reveal-logic">
    (function () {
      const hero = document.querySelector('.future-home-hero');
      const title = document.querySelector('.future-home-title');
      if (!hero || !title) return;

      // 1. Trigger Entrance for the entire section
      setTimeout(() => {
        hero.classList.add('is-glass-loaded');
      }, 150);


      // ═══ Section 2: Precise Reveal on Scroll ═══
      const dirSection = document.getElementById('home-directions');
      const cardGrid = document.querySelector('.future-card-grid');
      if (!dirSection || !cardGrid) return;

      const revealObserver = new IntersectionObserver((entries) => {
        entries.forEach(entry => {
          if (entry.isIntersecting) {
            dirSection.classList.add('is-directions-loaded');
            revealObserver.unobserve(entry.target);
          }
        });
      }, {
        threshold: 0.25, // Trigger reveal when a quarter of the grid is visible
        rootMargin: '0px 0px -20px 0px'
      });

      revealObserver.observe(cardGrid);

      // ═══ Section 10: Dynamic Impact Form ═══
      const formSection = document.getElementById('home-form');
      if (formSection) {
        const formObserver = new IntersectionObserver((entries) => {
          entries.forEach(entry => {
            if (entry.isIntersecting) {
              formSection.classList.add('is-form-revealed');
              formObserver.unobserve(entry.target);
            }
          });
        }, { threshold: 0.35 });
        formObserver.observe(formSection);
      }
    })();

    // Hero animation via GSAP
    (function () {
      function run() {
        console.log('[HERO ANIM] run called, gsap:', typeof gsap);
        if (typeof gsap === 'undefined') { console.log('[HERO ANIM] gsap not loaded, retrying...'); setTimeout(run, 50); return; }

        // Split heading into words
        var h1 = document.querySelector('.heading_hero');
        console.log('[HERO ANIM] h1 found:', !!h1);
        if (!h1) { console.log('[HERO ANIM] h1 NOT FOUND, aborting'); return; }
        var text = h1.textContent.trim();
        h1.innerHTML = text.split(/\s+/).map(function (w) {
          return '<span class="hero-word">' + w + '</span>';
        }).join(' ');

        // Force hide via direct style.cssText (bypasses all:unset)
        function forceStyle(sel, css) {
          document.querySelectorAll(sel).forEach(function (el) {
            el.style.cssText += ';' + css;
          });
        }

        forceStyle('.hero-partner-tag', 'opacity:0;clip-path:inset(0 100% 0 0);');
        forceStyle('.heading_hero .hero-word', 'opacity:0;transform:translateY(100%) rotateX(-60deg);transform-origin:bottom center;');
        forceStyle('.hero-compact .subheading', 'opacity:0;transform:translateY(20px);');
        forceStyle('.hero-compact .subheading.rich-text', 'opacity:0;transform:translateY(20px);');
        forceStyle('.hero-compact .button-group', 'opacity:0;transform:translateY(20px);');
        forceStyle('.hero-trust-row', 'opacity:0;transform:translateY(15px);');
        forceStyle('.hero-visual-wrap', 'opacity:0;filter:blur(20px);');

        // Animate
        var tl = gsap.timeline({ delay: 0.3 });

        tl.to('.hero-partner-tag', { opacity: 1, clipPath: 'inset(0 0% 0 0)', duration: 0.5, ease: 'power2.out' });
        tl.to('.heading_hero .hero-word', { opacity: 1, y: 0, rotationX: 0, duration: 0.5, ease: 'power2.out', stagger: 0.07 }, '-=0.2');
        tl.to('.hero-compact .subheading', { opacity: 1, y: 0, duration: 0.5, ease: 'power2.out' }, '-=0.1');
        tl.to('.hero-compact .button-group', { opacity: 1, y: 0, duration: 0.4, ease: 'power2.out' }, '-=0.2');
        tl.to('.hero-trust-row', { opacity: 1, y: 0, duration: 0.4, ease: 'power2.out' }, '-=0.2');
        tl.to('.hero-visual-wrap', { opacity: 1, filter: 'blur(0px)', duration: 0.8, ease: 'power2.out' }, 0.5);

        console.log('[HERO ANIM] timeline started');
      }

      if (document.readyState === 'complete') { setTimeout(run, 100); }
      else { window.addEventListener('load', function () { setTimeout(run, 100); }); }
    })();
  </script>
  <script id="scroll-observer">
    document.addEventListener('DOMContentLoaded', () => {
      const observerOptions = {
        threshold: 0.12,
        rootMargin: '0px 0px -50px 0px'
      };

      const observer = new IntersectionObserver((entries) => {
        entries.forEach(entry => {
          if (entry.isIntersecting) {
            entry.target.classList.add('is-visible');
          }
        });
      }, observerOptions);

      document.querySelectorAll('.anim-bounce, .glow-left, .glow-item, .zig-head, .zig-row, .cine-photo, .tw-head, .tw-card, .cr-head, .cr-featured, .cr-mini, .v4-top, .v4-card, .faq-l-anim, .faq-i-anim, .v1-card-cta, .future-review-card').forEach(el => observer.observe(el));
    });
  </script>
  <script>
    (function() {
      var nav = document.querySelector('.cmdf5-inspired-nav');
      if (!nav) return;
      var threshold = 30;
      var scrolled = false;
      function check() {
        var s = window.scrollY > threshold;
        if (s !== scrolled) {
          scrolled = s;
          nav.classList.toggle('nav-scrolled', s);
        }
      }
      window.addEventListener('scroll', check, { passive: true });
      check();
    })();
  </script>
  @include('site.partials.lead-popup')
  {!! $bodyEndPlugins ?? '' !!}
</body>

</html>
